        const exists = (rules?.exists && typeof rules.exists === 'object' && !Array.isArray(rules.exists)) ? rules.exists : {};
        if (exists[kind] !== false) return false;
        return metaAllowsEmit(rules?.ruleMeta?.metaphysics?.[kind] || {});
