        const normalizeEntity = (value = '') => String(value || '')
            .replace(/^[\s,.;:!?()[\]{}"'`~\-]+|[\s,.;:!?()[\]{}"'`~\-]+$/g, '')
            .replace(/(?:에게서는|에게서|에게는|에게|한테는|한테|께서는|께서|으로는|에서는|에는|에서|부터|까지|처럼|으로|하고|이랑|랑|은|는|이|가|을|를|의|도|로|만)$/u, '')
