            if (['secret', 'hidden', 'private'].includes(normalized)) return 'secret';
            if (['pov', 'limited', 'restricted', 'entity_only'].includes(normalized)) return 'pov';
            if (SECRET_RE.test(String(text || ''))) return 'secret';
