                id: compact(source.id || '', 80),
                title,
                content,
                about,
                owner: normalizeViewerId(source.owner || 'user') || 'user',
                knownBy: knownBy.length ? knownBy : ['user'],
                sensitivity: compact(source.sensitivity || 'normal', 40) || 'normal',
