                ...sharedConflict.map(v => `conflict:${v}`),
                ...sharedRelationDelta.map(v => `relation_delta:${v}`),
                ...sharedWorldSignature.map(v => `world_signature:${v}`),
                ...sharedWorldRules.map(v => `world_rule:${v}`),
