                            ...(rebuilt.source || {}),
                            rebuildReason: 'semantic_graph_v2_schema',
                            previousSchema: String(runtimeExisting?.schema || ''),
                            previousVersion: Number(runtimeExisting?.version || 0) || 0,
                            previousEdgeCount: hmeGraphEdges(runtimeExisting).length
