                        directFocusNames: uniqLimit(vars?.directFocusNames || vars?.focusNames || [], 24),
                        relatedFocusNames: uniqLimit(vars?.relatedFocusNames || [], 24),
                        narrativeArcKeys: uniqLimit(vars?.narrativeArcKeys || [], 12),
                        topK,
                        kindPlan: hybridKindPlan,
