                        index,
                        entry,
                        meta,
                        payload,
                        text,
                        hybridRow,
                        recency,
                        importance,
                        intentBonus,
                        recallBucket,
                        effectiveRecency,
                        hybridAlignment,
                        hybridBoost,
                        hmeGraphBoostInfo,
                        hmeGraphPreset,
                        hmeGraphBoost
