                            buckets: hybridRow.hybridLite.buckets || [],
                            liteScore: Number(hybridRow.hybridLite.score || 0),
                            boost: hybridBoost,
                            alignment: hybridAlignment,
                            kindPlan: hybridKindPlan,
                            reasons: hybridRow.hybridLite.reasons || []
